import DefaultTheme from 'vitepress/theme'
import type { Theme } from 'vitepress'
import { onMounted, onUnmounted, nextTick } from 'vue'
import './styles/modern.css'
import ToolGrid from './components/ToolGrid.vue'
import ToolCard from './components/ToolCard.vue'

// 婊氬姩瑙﹀彂鍔ㄧ敾绯荤粺
function initScrollAnimations() {
  const animatedElements = document.querySelectorAll(
    '.scroll-animate, .scroll-animate-left, .scroll-animate-right, .scroll-animate-scale, .scroll-animate-fade'
  )

  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add('is-visible')
          // 鍙€夛細鍔ㄧ敾瑙﹀彂鍚庡彇娑堣瀵?          // observer.unobserve(entry.target)
        }
      })
    },
    {
      threshold: 0.1,
      rootMargin: '0px 0px -50px 0px'
    }
  )

  animatedElements.forEach((el) => observer.observe(el))

  return observer
}

// 榧犳爣璺熼殢鍏夋檿鏁堟灉
function initMouseGlow() {
  // 妫€娴嬫槸鍚︿负瑙︽懜璁惧
  const isTouchDevice = window.matchMedia('(hover: none)').matches
  if (isTouchDevice) return

  const glowElements = document.querySelectorAll('.mouse-glow, .VPFeature')

  const handleMouseMove = (e: MouseEvent, el: Element) => {
    const rect = el.getBoundingClientRect()
    const x = ((e.clientX - rect.left) / rect.width) * 100
    const y = ((e.clientY - rect.top) / rect.height) * 100
    ;(el as HTMLElement).style.setProperty('--mouse-x', `${x}%`)
    ;(el as HTMLElement).style.setProperty('--mouse-y', `${y}%`)
  }

  glowElements.forEach((el) => {
    el.addEventListener('mousemove', (e) => handleMouseMove(e as MouseEvent, el))
  })

  return { glowElements, handleMouseMove }
}

export default {
  extends: DefaultTheme,
  enhanceApp({ app }) {
    app.component('ToolGrid', ToolGrid)
    app.component('ToolCard', ToolCard)
  },
  setup() {
    let scrollObserver: IntersectionObserver | null = null
    let mouseListeners: { glowElements: NodeListOf<Element>; handleMouseMove: (e: MouseEvent, el: Element) => void } | null = null

    onMounted(() => {
      // 绛夊緟 DOM 鏇存柊瀹屾垚
      nextTick(() => {
        scrollObserver = initScrollAnimations()
        mouseListeners = initMouseGlow()
      })
    })

    onUnmounted(() => {
      if (scrollObserver) {
        scrollObserver.disconnect()
      }
    })
  }
} satisfies Theme

