.rotating-border > * {
  position: relative;
  z-index: 1;
}

/* ============================================
   鍔ㄧ敾鍏抽敭甯?   ============================================ */

/* 娣″叆涓婄Щ鍔ㄧ敾 */
@keyframes fade-in-up {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-fade-in-up {
  animation: fade-in-up 0.6s ease-out forwards;
}

/* 鑴夊啿鍏夋檿鍔ㄧ敾 */
@keyframes pulse-glow {
  0%, 100% {
    box-shadow: 0 0 20px rgba(59, 130, 246, 0.3);
  }
  50% {
    box-shadow: 0 0 40px rgba(59, 130, 246, 0.5), 0 0 60px rgba(6, 182, 212, 0.3);
  }
}

.animate-pulse-glow {
  animation: pulse-glow 2s ease-in-out infinite;
}

/* 缃戞牸绉诲姩鍔ㄧ敾 */
@keyframes grid-move {
  0% {
    transform: perspective(var(--grid-perspective)) rotateX(var(--grid-rotate-x)) translateY(0);
  }
  100% {
    transform: perspective(var(--grid-perspective)) rotateX(var(--grid-rotate-x)) translateY(var(--grid-size));
  }
}

/* 娓愬彉娴佸姩鍔ㄧ敾 */
@keyframes gradient-shift {
  0% {
    background-position: 0% 50%;
  }
  50% {
    background-position: 100% 50%;
  }
  100% {
    background-position: 0% 50%;
  }
}

.animate-gradient {
  background-size: 200% 200%;
  animation: gradient-shift 3s ease infinite;
}

/* 娴姩鍔ㄧ敾 */
@keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-10px);
  }
}

.animate-float {
  animation: float 3s ease-in-out infinite;
}

/* 闂儊鍔ㄧ敾 */
@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

.animate-shimmer {
  background: linear-gradient(
    90deg,
    transparent 0%,
    rgba(255, 255, 255, 0.1) 50%,
    transparent 100%
  );
  background-size: 200% 100%;
  animation: shimmer 2s infinite;
}

/* ============================================
   鍔ㄧ敾寤惰繜宸ュ叿绫?   ============================================ */
.delay-100 { animation-delay: 100ms; }
.delay-200 { animation-delay: 200ms; }
.delay-300 { animation-delay: 300ms; }
.delay-400 { animation-delay: 400ms; }
.delay-500 { animation-delay: 500ms; }
.delay-600 { animation-delay: 600ms; }
.delay-700 { animation-delay: 700ms; }
.delay-800 { animation-delay: 800ms; }

/* ============================================
   Phase 3: 婊氬姩瑙﹀彂鍔ㄧ敾绯荤粺 (Task 7)
   ============================================ */

/* 鍩虹婊氬姩瑙﹀彂鍔ㄧ敾 */
.scroll-animate {
  opacity: 0;
  transform: translateY(40px);
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  transition-delay: var(--stagger-delay, 0s);
  will-change: opacity, transform;
}

.scroll-animate.is-visible {
  opacity: 1;
  transform: translateY(0);
}

/* 浠庡乏渚ф粦鍏?*/
.scroll-animate-left {
  opacity: 0;
  transform: translateX(-40px);
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  transition-delay: var(--stagger-delay, 0s);
  will-change: opacity, transform;
}

.scroll-animate-left.is-visible {
  opacity: 1;
  transform: translateX(0);
}

/* 浠庡彸渚ф粦鍏?*/
.scroll-animate-right {
  opacity: 0;
  transform: translateX(40px);
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  transition-delay: var(--stagger-delay, 0s);
  will-change: opacity, transform;
}

.scroll-animate-right.is-visible {
  opacity: 1;
  transform: translateX(0);
}

/* 缂╂斁杩涘叆 */
.scroll-animate-scale {
  opacity: 0;
  transform: scale(0.9);
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  transition-delay: var(--stagger-delay, 0s);
  will-change: opacity, transform;
}

.scroll-animate-scale.is-visible {
  opacity: 1;
  transform: scale(1);
}

/* 娣″叆鍔ㄧ敾 */
.scroll-animate-fade {
  opacity: 0;
  transition: opacity 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  transition-delay: var(--stagger-delay, 0s);
  will-change: opacity;
}

.scroll-animate-fade.is-visible {
  opacity: 1;
}

/* Stagger 寤惰繜宸ュ叿绫?*/
.stagger-1 { --stagger-delay: 0.1s; }
.stagger-2 { --stagger-delay: 0.2s; }
.stagger-3 { --stagger-delay: 0.3s; }
.stagger-4 { --stagger-delay: 0.4s; }
.stagger-5 { --stagger-delay: 0.5s; }
.stagger-6 { --stagger-delay: 0.6s; }

/* ============================================
   Phase 3: 楂樼骇鎮仠浜や簰 (Task 8)
   ============================================ */

/* 榧犳爣璺熼殢鍏夋檿 - JS 杈呭姪鏍峰紡 */
.mouse-glow {
  position: relative;
  --mouse-x: 50%;
  --mouse-y: 50%;
}

.mouse-glow::before {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(
    400px circle at var(--mouse-x) var(--mouse-y),
    rgba(59, 130, 246, 0.15),
    transparent 50%
  );
  opacity: 0;
  transition: opacity 0.3s ease;
  pointer-events: none;
  z-index: 0;
  border-radius: inherit;
}

.mouse-glow:hover::before {
  opacity: 1;
}

/* 绉诲姩绔Е鎽镐氦浜掍紭鍖?- hover: none 璁惧 */
@media (hover: none) {
  .mouse-glow::before {
    display: none;
  }

  .VPFeature::after {
    display: none;
  }

  .glass-card:hover {
    transform: none;
  }

  .VPFeature:hover {
    transform: none;
  }

  .VPHero .VPButton:hover {
    transform: none !important;
  }
}

/* 瑙︽懜鍙嬪ソ鐨勭偣鍑诲尯鍩?*/
@media (hover: none) and (pointer: coarse) {
  .VPButton,
  .glass-btn,
  .VPLink {
    min-height: 44px;
    min-width: 44px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }

  .VPNav .VPNavBarMenuLink {
    padding: 0.75rem 1rem !important;
  }
}

/* ============================================
   prefers-reduced-motion 鏀寔
   ============================================ */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .scroll-animate,
  .scroll-animate-left,
  .scroll-animate-right,
  .scroll-animate-scale {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .grid-bg::before {
    animation: none;
  }

  .rotating-border::before {
    animation: none;
  }
}

/* ============================================
