export function useTiltEffect(
  elementRef: Ref<HTMLElement | null>,
  maxTilt: number = 10
): {
  style: Ref<CSSProperties>
  isHovering: Ref<boolean>
} {
  const isHovering = ref(false)
  const tiltX = ref(0)
  const tiltY = ref(0)

  const style = computed<CSSProperties>(() => ({
    transform: isHovering.value
      ? `perspective(1000px) rotateX(${tiltX.value}deg) rotateY(${tiltY.value}deg) scale3d(1.02, 1.02, 1.02)`
      : 'perspective(1000px) rotateX(0deg) rotateY(0deg) scale3d(1, 1, 1)',
    transition: isHovering.value ? 'transform 0.1s ease-out' : 'transform 0.3s ease-out',
    transformStyle: 'preserve-3d'
  }))

  const handleMouseMove = (event: MouseEvent) => {
    const el = elementRef.value
    if (!el) return

    const rect = el.getBoundingClientRect()
    const centerX = rect.left + rect.width / 2
    const centerY = rect.top + rect.height / 2

    const percentX = (event.clientX - centerX) / (rect.width / 2)
    const percentY = (event.clientY - centerY) / (rect.height / 2)

    tiltY.value = percentX * maxTilt
    tiltX.value = -percentY * maxTilt
  }

  const handleMouseEnter = () => {
    isHovering.value = true
  }

  const handleMouseLeave = () => {
    isHovering.value = false
    tiltX.value = 0
    tiltY.value = 0
  }

  onMounted(() => {
    const el = elementRef.value
    if (!el) return

    el.addEventListener('mouseenter', handleMouseEnter)
    el.addEventListener('mouseleave', handleMouseLeave)
    el.addEventListener('mousemove', handleMouseMove)
  })

  onUnmounted(() => {
    const el = elementRef.value
    if (!el) return

    el.removeEventListener('mouseenter', handleMouseEnter)
    el.removeEventListener('mouseleave', handleMouseLeave)
    el.removeEventListener('mousemove', handleMouseMove)
  })

  return {
    style,
    isHovering
  }
}

