 * 榧犳爣璺熼殢鍏夋檿鏁堟灉
 * 鐢熸垚闅忛紶鏍囩Щ鍔ㄧ殑寰勫悜娓愬彉鑳屾櫙
 */
export function useMouseGlow(
  elementRef: Ref<HTMLElement | null>,
  color: string = 'rgba(139, 92, 246, 0.3)'
): {
  style: Ref<CSSProperties>
  updatePosition: (x: number, y: number) => void
} {
  const glowX = ref(50)
  const glowY = ref(50)

  const style = computed<CSSProperties>(() => ({
    background: `radial-gradient(circle at ${glowX.value}% ${glowY.value}%, ${color} 0%, transparent 50%)`,
    transition: 'background 0.15s ease-out'
  }))

  const updatePosition = (x: number, y: number) => {
    const el = elementRef.value
    if (!el) return

    const rect = el.getBoundingClientRect()
    glowX.value = ((x - rect.left) / rect.width) * 100
    glowY.value = ((y - rect.top) / rect.height) * 100
  }

  return {
    style,
    updatePosition
  }
}

export default useMousePosition

